app.post('/v1/levels/complete', requireApiKey, verifyClientSignature, (req, res) => {
  const errors = validateCompletionBody(req.body);
  if (errors.length) return jsonError(res, 400, 'VALIDATION_ERROR', 'Invalid completion payload', errors);

  const { playerId, score, timeMs, attemptId, clientTimeMs } = req.body;
  const levelId = normalizeLevelId(req.body.levelId);

  const completionKey = makeCompletionKey(playerId, attemptId);
  const existing = db.levelCompletions.get(completionKey);
  if (existing) {
    return res.json({
      ok: true,
      completion: existing.public,
      rewardPreview: existing.reward,
      idempotent: true,
    });
  }

  const player = getOrCreatePlayer(playerId);

  const completionId = crypto.randomUUID();
  const serverTimeMs = nowMs();

  const reward = computeRewards({ levelId, score, timeMs });

  const completion = {
    completionId,
    playerId,
    levelId,
    score,
    timeMs,
    attemptId,
    clientTimeMs: clientTimeMs || null,
    serverReceivedAt: serverTimeMs,
    reward,
    status: 'COMPLETED',
  };

  const publicCompletion = {
    completionId,
    playerId,
    levelId,
    score,
    timeMs,
    attemptId,
    receivedAt: serverTimeMs,
    status: completion.status,
  };

  db.levelCompletions.set(completionKey, {
    completion,
    public: publicCompletion,
    reward,
  });

  player.progression.totalCompletions += 1;
  const levelNum = parseInt(levelId, 10);
  if (Number.isFinite(levelNum)) {
    player.progression.highestLevelCompleted = Math.max(player.progression.highestLevelCompleted, levelNum);
  }
  player.lastCompletionAt = serverTimeMs;
  player.updatedAt = serverTimeMs;

  res.status(201).json({
    ok: true,
    completion: publicCompletion,
    rewardPreview: reward,
    claim: {
      endpoint: '/v1/rewards/claim',
      body: { playerId, completionId },
    },
  });
});

app.post('/v1/rewards/claim', requireApiKey, verifyClientSignature, (req, res) => {
  const body = req.body || {};
  const errors = [];
  if (!body.playerId || typeof body.playerId !== 'string' || body.playerId.length > 128) errors.push('playerId is required (string <= 128)');
  if (!body.completionId || typeof body.completionId !== 'string' || body.completionId.length > 128) errors.push('completionId is required (string <= 128)');
  if (errors.length) return jsonError(res, 400, 'VALIDATION_ERROR', 'Invalid claim payload', errors);

  const { playerId, completionId } = body;
  const player = getOrCreatePlayer(playerId);

  let completionRecord = null;
  for (const v of db.levelCompletions.values()) {
    if (v.completion.completionId === completionId && v.completion.playerId === playerId) {
      completionRecord = v;
      break;
    }
  }
  if (!completionRecord) return jsonError(res, 404, 'NOT_FOUND', 'Completion not found');

  const claimKey = makeClaimKey(playerId, completionId);
  const existingClaim = db.rewardClaims.get(claimKey);
  if (existingClaim) {
    return res.json({
      ok: true,
      claim: existingClaim.public,
      wallet: existingClaim.wallet,
      idempotent: true,
    });
  }

  const reward = completionRecord.reward;

  applyRewardToPlayer(player, reward);

  const claimId = crypto.randomUUID();
  const claimedAt = nowMs();

  const claim = {
    claimId,
    playerId,
    completionId,
    rewardId: reward.rewardId,
    claimedAt,
    status: 'CLAIMED',
  };

  const wallet = {
    currency: { ...player.currency },
    inventory: { ...player.inventory },
  };

  db.rewardClaims.set(claimKey, {
    claim,
    public: claim,
    wallet,
  });

  res.status(201).json({
    ok: true,
    claim,
    reward,
    wallet,
  });
});

